<div class="panel"><div class="panel-head"><div><h2><?= htmlspecialchars($moduleDef['title']) ?></h2><p>CRUD básico com ordenação, ativação e edição.</p></div><a class="btn btn-primary" href="<?= base_url('/admin/module/' . $module . '/new') ?>">Novo item</a></div><div class="table-wrap"><table><thead><tr><th>ID</th><th>Título</th><th>Status</th><th>Ordem</th><th>Ações</th></tr></thead><tbody><?php foreach ($items as $item): ?><?php $label = $item['title'] ?? $item['name'] ?? $item['author_name'] ?? 'Item'; ?><tr><td><?= (int) ($item['id'] ?? 0) ?></td><td><?= htmlspecialchars($label) ?></td><td><?= !empty($item['is_active']) ? 'Ativo' : 'Inativo' ?></td><td><?= htmlspecialchars((string) ($item['sort_order'] ?? '0')) ?></td><td class="actions"><a href="<?= base_url('/admin/module/' . $module . '/edit/' . ($item['id'] ?? 0)) ?>">Editar</a><a href="<?= base_url('/admin/module/' . $module . '/toggle/' . ($item['id'] ?? 0)) ?>">Ativar/Inativar</a><a href="<?= base_url('/admin/module/' . $module . '/delete/' . ($item['id'] ?? 0)) ?>" onclick="return confirm('Excluir este item?')">Excluir</a></td></tr><?php endforeach; ?><?php if (!$items): ?><tr><td colspan="5">Nenhum registro encontrado.</td></tr><?php endif; ?></tbody></table></div></div>
